import{_ as a,c as i,o as d,a1 as e}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"平台與整合：macOS、Windows、Linux 終端機特性與支援詳解 | opencode-notify","description":"學習 opencode-notify 在 macOS、Windows、Linux 上的功能差異，掌握終端機支援（37+ 終端機模擬器）、焦點偵測、點擊聚焦和自訂音效等平台特性。本章節包含平台功能比較、終端機偵測機制和設定指南，幫助你根據作業系統和終端機類型最佳化通知體驗，提升工作效率。","frontmatter":{"title":"平台與整合：macOS、Windows、Linux 終端機特性與支援詳解 | opencode-notify","sidebarTitle":"適配你的平台","subtitle":"平台與整合","description":"學習 opencode-notify 在 macOS、Windows、Linux 上的功能差異，掌握終端機支援（37+ 終端機模擬器）、焦點偵測、點擊聚焦和自訂音效等平台特性。本章節包含平台功能比較、終端機偵測機制和設定指南，幫助你根據作業系統和終端機類型最佳化通知體驗，提升工作效率。","tags":["平台特性","終端機支援","系統相容"],"prerequisite":["start-quick-start","start-how-it-works"],"order":2},"headers":[],"relativePath":"zh-tw/kdcokenny/opencode-notify/platforms/index.md","filePath":"zh-tw/kdcokenny/opencode-notify/platforms/index.md"}'),o={name:"zh-tw/kdcokenny/opencode-notify/platforms/index.md"};function l(r,t,n,s,h,c){return d(),i("div",null,[...t[0]||(t[0]=[e('<h1 id="平台與整合" tabindex="-1">平台與整合 <a class="header-anchor" href="#平台與整合" aria-label="Permalink to &quot;平台與整合&quot;">​</a></h1><p>本章節幫助你了解 opencode-notify 在不同作業系統上的功能差異，掌握平台特定設定，以及如何讓你的終端機發揮最佳效能。</p><h2 id="學習路徑" tabindex="-1">學習路徑 <a class="header-anchor" href="#學習路徑" aria-label="Permalink to &quot;學習路徑&quot;">​</a></h2><h3 id="_1-macos-平台特性" tabindex="-1">1. <a href="./../macos/">macOS 平台特性</a> <a class="header-anchor" href="#_1-macos-平台特性" aria-label="Permalink to &quot;1. [macOS 平台特性](../macos/)&quot;">​</a></h3><p>全面了解 macOS 上的進階功能，包括智慧焦點偵測、點擊通知聚焦和自訂音效。</p><ul><li>焦點偵測：自動判斷終端機是否為當前活動視窗</li><li>點擊聚焦：點擊通知後自動切換到終端機</li><li>自訂音效：為不同事件設定專屬音效</li><li>37+ 終端機支援：包括 Ghostty、iTerm2、VS Code 整合終端機等</li></ul><h3 id="_2-windows-平台特性" tabindex="-1">2. <a href="./../windows/">Windows 平台特性</a> <a class="header-anchor" href="#_2-windows-平台特性" aria-label="Permalink to &quot;2. [Windows 平台特性](../windows/)&quot;">​</a></h3><p>掌握 Windows 平台的通知基礎和設定方法。</p><ul><li>原生通知：使用 Windows 10/11 通知中心</li><li>通知權限：確保 OpenCode 有發送通知的權限</li><li>基礎設定：Windows 環境下的設定檔位置</li><li>限制說明：Windows 暫不支援焦點偵測功能</li></ul><h3 id="_3-linux-平台特性" tabindex="-1">3. <a href="./../linux/">Linux 平台特性</a> <a class="header-anchor" href="#_3-linux-平台特性" aria-label="Permalink to &quot;3. [Linux 平台特性](../linux/)&quot;">​</a></h3><p>了解 Linux 平台的通知機制和依賴安裝。</p><ul><li>libnotify 整合：使用 notify-send 發送通知</li><li>桌面環境支援：GNOME、KDE Plasma、XFCE 等主流環境</li><li>依賴安裝：不同發行版的安裝指令</li><li>限制說明：Linux 暫不支援焦點偵測功能</li></ul><h3 id="_4-支援的終端機" tabindex="-1">4. <a href="./../terminals/">支援的終端機</a> <a class="header-anchor" href="#_4-支援的終端機" aria-label="Permalink to &quot;4. [支援的終端機](../terminals/)&quot;">​</a></h3><p>查看所有 37+ 支援的終端機模擬器，了解自動偵測機制。</p><ul><li>終端機偵測：如何自動辨識你的終端機類型</li><li>終端機清單：完整的支援終端機清單</li><li>手動設定：當自動偵測失敗時如何手動指定</li><li>特殊終端機：VS Code 整合終端機、遠端 SSH 會話的處理</li></ul><h2 id="前置條件" tabindex="-1">前置條件 <a class="header-anchor" href="#前置條件" aria-label="Permalink to &quot;前置條件&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">學習本章節前，請確保已完成</p><ul><li>✅ <strong><a href="./../../start/quick-start/">快速開始</a></strong>：已完成 opencode-notify 安裝</li><li>✅ <strong><a href="./../../start/how-it-works/">工作原理</a></strong>：理解四種通知類型和智慧過濾機制</li></ul></div><h2 id="平台選擇建議" tabindex="-1">平台選擇建議 <a class="header-anchor" href="#平台選擇建議" aria-label="Permalink to &quot;平台選擇建議&quot;">​</a></h2><p>根據你的作業系統選擇對應的章節：</p><table tabindex="0"><thead><tr><th>作業系統</th><th>推薦學習順序</th><th>核心功能</th></tr></thead><tbody><tr><td><strong>macOS</strong></td><td>1. macOS 平台特性 → 4. 支援的終端機</td><td>焦點偵測、點擊聚焦、自訂音效</td></tr><tr><td><strong>Windows</strong></td><td>2. Windows 平台特性 → 4. 支援的終端機</td><td>原生通知、基礎設定</td></tr><tr><td><strong>Linux</strong></td><td>3. Linux 平台特性 → 4. 支援的終端機</td><td>libnotify 整合、依賴安裝</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">通用建議</p><p>無論你使用哪個平台，第 4 課「支援的終端機」都值得學習，它能幫助你理解終端機偵測機制，解決設定問題。</p></div><h2 id="功能對比表" tabindex="-1">功能對比表 <a class="header-anchor" href="#功能對比表" aria-label="Permalink to &quot;功能對比表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>功能</th><th>macOS</th><th>Windows</th><th>Linux</th></tr></thead><tbody><tr><td>原生通知</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>終端機焦點偵測</td><td>✅</td><td>❌</td><td>❌</td></tr><tr><td>點擊通知聚焦</td><td>✅</td><td>❌</td><td>❌</td></tr><tr><td>自訂音效</td><td>✅</td><td>✅</td><td>✅ (部分)</td></tr><tr><td>靜音時段</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>父會話檢查</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>37+ 終端機支援</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>自動終端機偵測</td><td>✅</td><td>✅</td><td>✅</td></tr></tbody></table><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>完成本章節後，你將了解不同平台的功能差異和設定方法。</p><p>建議繼續學習：</p><h3 id="進階設定" tabindex="-1"><a href="./../../advanced/config-reference/">進階設定</a> <a class="header-anchor" href="#進階設定" aria-label="Permalink to &quot;[進階設定](../../advanced/config-reference/)&quot;">​</a></h3><p>深入學習設定檔的所有選項，掌握進階設定技巧。</p><ul><li>完整設定參考：所有設定項的詳細說明</li><li>靜音時段詳解：如何設定和工作原理</li><li>終端機偵測原理：自動偵測的內部機制</li><li>進階用法：設定技巧和最佳實踐</li></ul><h3 id="故障排除" tabindex="-1"><a href="./../../faq/troubleshooting/">故障排除</a> <a class="header-anchor" href="#故障排除" aria-label="Permalink to &quot;[故障排除](../../faq/troubleshooting/)&quot;">​</a></h3><p>遇到問題時，查看常見故障的解決方案。</p><ul><li>通知不顯示：權限和系統設定問題</li><li>焦點偵測失效：終端機設定和偵測機制</li><li>設定錯誤：設定檔格式和欄位說明</li><li>音效問題：音效設定和系統相容性</li></ul><div class="info custom-block"><p class="custom-block-title">學習路徑建議</p><p>如果你剛開始使用，建議按照 <strong>平台章節 → 進階設定 → 故障排除</strong> 的順序學習。如果你遇到具體問題，可以直接跳轉到故障排除章節。</p></div>',33)])])}const f=a(o,[["render",l]]);export{p as __pageData,f as default};
